import TencentCloudChat from '@tencentcloud/lite-chat';
import { BaseService } from '../core/IMService';
import { EVENT } from '../constants';

import type { Conversation, Message } from '@tencentcloud/lite-chat';
import { GroupService } from './GroupService';


export class ConversationService extends BaseService {
  private _conversationList:any[] = [];
  mount(): void {
    this.ctx.chat.on(TencentCloudChat.EVENT.CONVERSATION_LIST_UPDATED, this.handleConversationListUpdated);
    this.ctx.chat.on(TencentCloudChat.EVENT.CONVERSATION_GROUP_LIST_UPDATED, this.handleConversationGroupListUpdated);
    this.ctx.chat.on(TencentCloudChat.EVENT.CONVERSATION_IN_GROUP_UPDATED, this.handleConversationInGroupUpdated);
  }

  unmount(): void {
    console.log('unmount:', this);
    this.ctx.chat.off(TencentCloudChat.EVENT.CONVERSATION_LIST_UPDATED, this.handleConversationListUpdated);
    this.ctx.chat.off(TencentCloudChat.EVENT.CONVERSATION_GROUP_LIST_UPDATED, this.handleConversationGroupListUpdated);
    this.ctx.chat.off(TencentCloudChat.EVENT.CONVERSATION_IN_GROUP_UPDATED, this.handleConversationInGroupUpdated);
  }

  private handleConversationListUpdated = (e: any): void => {
    this._conversationList = e.data.conversationList;
    this.ctx.mitt.emit(TencentCloudChat.EVENT.CONVERSATION_LIST_UPDATED, e.data);
    this.ctx.mitt.emit(EVENT.CONVERSATION, this._conversationList);
  }

  private handleConversationGroupListUpdated = (e: any): void => {
    // console.log(e.data); // 全量的会话分组名列表, 在(创建会话分组、删除会话分组、重命名会话分组)会触发.
    this.ctx.mitt.emit(TencentCloudChat.EVENT.CONVERSATION_GROUP_LIST_UPDATED, e.data);
  }
  private handleConversationInGroupUpdated = (e: any): void => {
    const { groupName, conversationList }  = e.data;
    this.ctx.mitt.emit(TencentCloudChat.EVENT.CONVERSATION_IN_GROUP_UPDATED, e.data);
  }

  async modifyMessage(message:Message): Promise<Message | null>{
    const { success } = await this.ctx.chat.modifyMessage(message);
    return success?.data?.message ?? null;
  }
  async getMessageList(options: { conversationID: string, nextReqMessageID?:string }): Promise<{ messageList: Message[], nextReqMessageID:string, isCompleted: boolean } | null>{
    const { success } = await this.ctx.chat.getMessageList(options);
    return success?.data ?? null;
  }
  async getMessageListHopping(options: {conversationID: string, sequence?: number, time?: number, direction?: number;}): Promise<{ messageList: Message[], nextMessageSeq?:string, nextMessageTime?:number, isCompleted: boolean } | null>{
    const { success } = await this.ctx.chat.getMessageListHopping(options);
    return success?.data ?? null;
  }
  async sendMessageReadReceipt(messageList: Message[]): Promise<boolean>{
    const { success } = await this.ctx.chat.sendMessageReadReceipt(messageList);
    return success ? true : false;
  }
  async getMessageReadReceiptList(messageList: Message[]): Promise<Message[]>{
    const { success } = await this.ctx.chat.getMessageReadReceiptList(messageList);
    return success?.data?.messageList ?? [];
  }
  async getGroupMessageReadMemberList(options: { message: Message, cursor: string, filter: number, count: number }): Promise<{  isCompleted:boolean, cursor:string, messageID:string, readUserIDList:any[], unreadUserIDList:any[] } | null>{
    const { success } = await this.ctx.chat.getGroupMessageReadMemberList(options);
    return success?.data ?? null;
  }
  findMessage(messageID:string): Message | null{
    return this.ctx.chat.findMessage(messageID);
  }
  async setMessageRead(options: { conversationID: string }): Promise<boolean>{
    const { success } = await this.ctx.chat.setMessageRead(options);
    return success ? true : false;
  }

  async getConversationList(options?: Array<string> | any): Promise<Conversation[]> {
    const { success } = await this.ctx.chat.getConversationList(options);
    const list = (success?.data?.conversationList ?? []).map((item:any) => {
      item.groupProfile = GroupService.handleGroupInfo(item.groupProfile);
      return item;
    });
    this._conversationList = list;
    this.ctx.mitt.emit(EVENT.CONVERSATION, this._conversationList);
    return list;
  }

  async getConversationProfile(conversationID: string): Promise<Conversation | null> {
    const { success } = await this.ctx.chat.getConversationProfile(conversationID);
    return success?.data?.conversation ?? null;
  }

  async deleteConversation(options: string | any): Promise<boolean>{
    const { success } = await this.ctx.chat.deleteConversation(options);
    if(success){
      const list = await this.getConversationList();
      this.ctx.mitt.emit(TencentCloudChat.EVENT.CONVERSATION_LIST_UPDATED, list);
    }
    return success ? true : false;
  }

  async setConversationDraft(options: { conversationID: string, draftText: string }):Promise<boolean>{
    const { success } = await this.ctx.chat.setConversationDraft(options);
    return success ? true : false;
  }

  async clearHistoryMessage(conversationID: string):Promise<boolean>{
    const { success } = await this.ctx.chat.clearHistoryMessage(conversationID);
    return success ? true : false;
  }

  async pinConversation(options: {conversationID: string, isPinned: boolean}):Promise<boolean>{
    const { success } = await this.ctx.chat.pinConversation(options);
    return success ? true : false;
  }

  async setAllMessageRead(options: { scope: TencentCloudChat.TYPES }):Promise<boolean>{
    const { success } = await this.ctx.chat.setAllMessageRead(options);
    return success ? true : false;
  }

  async setMessageRemindType(options: { groupID?: string, userIDList?: Array<string>, messageRemindType: any }):Promise<boolean>{
    const { success } = await this.ctx.chat.setMessageRemindType(options);
    return success ? true : false;
  }
  async setAllReceiveMessageOpt(options: {
    messageRemindType?: any;
    startHour?: number;
    startMinute?: number;
    startSecond?: number;
    duration?: number;
    isRepeated?: boolean;
  }):Promise<boolean>{
    const { success } = await this.ctx.chat.setAllReceiveMessageOpt(options);
    return success ? true : false;
  }
  async getAllReceiveMessageOpt():Promise<{ messageRemindType: string, startTime: number, endTime: number, isRepeated: boolean } | null>{
    const { success } = await this.ctx.chat.getAllReceiveMessageOpt();
    return success?.data ?? null;
  }
  getTotalUnreadMessageCount():number{
    return this.ctx.chat.getTotalUnreadMessageCount();
  }

  async setConversationCustomData(options: { conversationIDList: string[], customData:string }): Promise<{  successConversationIDList:any[], failureConversationIDList:any[] } | null>{
    const { success } = await this.ctx.chat.setConversationCustomData(options);
    return success?.data ?? null;
  }
  async markConversation(options: { conversationIDList:string[], markType:number, enableMark:boolean }): Promise<{ successConversationIDList:any[], failureConversationIDList:any[] } | null>{
    const { success } = await this.ctx.chat.markConversation(options);
    return success?.data ?? null;
  }
  async getConversationGroupList(): Promise<string[]>{
    const { success } = await this.ctx.chat.getConversationGroupList();
    return success?.data ?? null;
  }
  async createConversationGroup(options: { conversationIDList: string[], groupName: string }): Promise<{ successConversationIDList:any[], failureConversationIDList:any[] } | null>{
    const { success } = await this.ctx.chat.createConversationGroup(options);
    return success?.data ?? null;
  }
  async deleteConversationGroup(groupName: string): Promise<boolean>{
    const { success } = await this.ctx.chat.deleteConversationGroup(groupName);
    return success ? true : false;
  }
  async renameConversationGroup(options: { oldName: string, newName: string }): Promise<boolean>{
    const { success } = await this.ctx.chat.renameConversationGroup(options);
    return success ? true : false;
  }
  async addConversationsToGroup(options: { conversationIDList: string[], groupName:string }): Promise<{ successConversationIDList:any[], failureConversationIDList:any[] } | null>{
    const { success } = await this.ctx.chat.addConversationsToGroup(options);
    return success?.data ?? null;
  }
  async deleteConversationsFromGroup(options: { conversationIDList: string[], groupName:string }): Promise<{ successConversationIDList:any[], failureConversationIDList:any[] } | null>{
    const { success } = await this.ctx.chat.deleteConversationsFromGroup(options);
    return success?.data ?? null;
  }
}
