import TencentCloudChat from '@tencentcloud/lite-chat';
import { BaseService } from '../core/IMService';

import type { Message } from '@tencentcloud/lite-chat';
import { EVENT } from '../constants';
import type { MessageFace, MessageFile, MessageGroupSystemNotice, MessageGroupTip, MessageImage, MessageLocation, MessageMerger, MessageSound, MessageText, MessageVideo } from '../types';
import type { MessageCustomDepartment, MessageCustomDoctor, MessageCustomPayment, MessageCustomUnknow, MessageCustomPatient, MessageCustomOrder, MessageCustomAdditionalFee, MessageCustomApproved, MessageCustomConsultation, MessageCustomDoctor2, MessageCustomThird, MessageCustomGroupNotice, MessageCustomHealthCard, MessageCustomRegistration, MessageCustomSystemNotice } from '../types';

type LiteMessage = Message & { isNewReceived?:boolean };
type MessageListCustomType = Array<LiteMessage|MessageCustomDepartment|MessageCustomDoctor|MessageCustomPayment|MessageCustomUnknow|MessageCustomPatient|MessageCustomOrder|MessageCustomAdditionalFee|MessageCustomApproved|MessageCustomConsultation|MessageCustomDoctor2|MessageCustomThird|MessageCustomGroupNotice|MessageCustomHealthCard|MessageCustomRegistration|MessageCustomSystemNotice|MessageFace|MessageFile|MessageGroupSystemNotice|MessageGroupTip|MessageImage|MessageLocation|MessageMerger|MessageSound|MessageText|MessageVideo>

export type ConversationType = TencentCloudChat.TYPES.CONV_GROUP | TencentCloudChat.TYPES.CONV_C2C

export class MessageService extends BaseService {
  private _nextReqMessageID:string | undefined  = undefined;
  private _messageList: MessageListCustomType = [];
  private _conversationID: any;
  
  mount(): void {
    this.ctx.chat.on(TencentCloudChat.EVENT.MESSAGE_RECEIVED, this.handleMessageReceived);
    this.ctx.chat.on(TencentCloudChat.EVENT.MESSAGE_MODIFIED, this.handleMessageModified);
    this.ctx.chat.on(TencentCloudChat.EVENT.MESSAGE_REVOKED, this.handleMessageRevoked);
    this.ctx.chat.on(TencentCloudChat.EVENT.MESSAGE_READ_BY_PEER, this.handleMessageReadByPeer);
    this.ctx.chat.on(TencentCloudChat.EVENT.MESSAGE_READ_RECEIPT_RECEIVED, this.handleMessageReadReceiptReceived);
    // this.ctx.chat.on(TencentCloudChat.EVENT.MESSAGE_EXTENSIONS_UPDATED, this.handleMessageExtensionsUpdated);
    // this.ctx.chat.on(TencentCloudChat.EVENT.MESSAGE_EXTENSIONS_DELETED, this.handleMessageExtensionsDeleted);
    // this.ctx.chat.on(TencentCloudChat.EVENT.MESSAGE_REACTIONS_UPDATED, this.handleMessageReactionsUpdated);
    this.ctx.chat.on(TencentCloudChat.EVENT.TOTAL_UNREAD_MESSAGE_COUNT_UPDATED, this.handleTotalUnreadMessageCountUpdated);
  }

  unmount(): void {
    this.ctx.chat.off(TencentCloudChat.EVENT.MESSAGE_RECEIVED, this.handleMessageReceived);
    this.ctx.chat.off(TencentCloudChat.EVENT.MESSAGE_MODIFIED, this.handleMessageModified);
    this.ctx.chat.off(TencentCloudChat.EVENT.MESSAGE_REVOKED, this.handleMessageRevoked);
    this.ctx.chat.off(TencentCloudChat.EVENT.MESSAGE_READ_BY_PEER, this.handleMessageReadByPeer);
    this.ctx.chat.off(TencentCloudChat.EVENT.MESSAGE_READ_RECEIPT_RECEIVED, this.handleMessageReadReceiptReceived);
    // this.ctx.chat.off(TencentCloudChat.EVENT.MESSAGE_EXTENSIONS_UPDATED, this.handleMessageExtensionsUpdated);
    // this.ctx.chat.off(TencentCloudChat.EVENT.MESSAGE_EXTENSIONS_DELETED, this.handleMessageExtensionsDeleted);
    // this.ctx.chat.off(TencentCloudChat.EVENT.MESSAGE_REACTIONS_UPDATED, this.handleMessageReactionsUpdated);
    this.ctx.chat.off(TencentCloudChat.EVENT.TOTAL_UNREAD_MESSAGE_COUNT_UPDATED, this.handleTotalUnreadMessageCountUpdated);
  }

  private handleMessageReceived = (e:any):void => {
    this._messageList.push(...e.data);
    this.updateMessageList(e.data);
    this.ctx.mitt.emit(TencentCloudChat.EVENT.MESSAGE_RECEIVED, e.data);
    this.ctx.mitt.emit(EVENT.MESSAGE, this._messageList);
  }
  private handleMessageModified = (e:any):void => {
    this.ctx.mitt.emit(TencentCloudChat.EVENT.MESSAGE_MODIFIED, e.data);
  }
  private handleMessageRevoked = (e:any):void => {
    this.ctx.mitt.emit(TencentCloudChat.EVENT.MESSAGE_REVOKED, e.data);
  }
  private handleMessageReadByPeer = (e:any):void => {
    this.ctx.mitt.emit(TencentCloudChat.EVENT.MESSAGE_READ_BY_PEER, e.data);
  }
  private handleMessageReadReceiptReceived = (e:any):void => {
    this.ctx.mitt.emit(TencentCloudChat.EVENT.MESSAGE_READ_RECEIPT_RECEIVED, e.data);
  }
  // private handleMessageExtensionsUpdated = (e:any):void => {}
  // private handleMessageExtensionsDeleted = (e:any):void => {}
  // private handleMessageReactionsUpdated = (e:any):void => {}
  private handleTotalUnreadMessageCountUpdated = (e:any):void => {
    this.ctx.mitt.emit(TencentCloudChat.EVENT.TOTAL_UNREAD_MESSAGE_COUNT_UPDATED, e.data);
  }

  private updateMessageList(list?:MessageListCustomType):MessageListCustomType{
    const isUnParsed = (message:Message) => message.type === "TIMCustomElem" && typeof message?.payload?.extension === "string";
    this._messageList = this._messageList.map(item => {
      item.isNewReceived = !!list?.find?.(o => o.ID === item.ID);
      // 增加一个isNewReceived属性用于区分当前消息是否是通过MESSAGE_RECEIVED获取到的最新消息.
      if(isUnParsed(item as  Message)){
        try{
          item.payload.extension = JSON.parse(item.payload.extension);
        }catch(e){
          this.ctx.logger.warn(`解析消息扩展数据失败 ${item?.payload?.extension}`);
          item.payload.extension = {};
        }
      }
      return item;
    }).map(item => {
      if(item.type === TencentCloudChat.TYPES.MSG_TEXT){
        return item as MessageText;
      }
      if(item.type === TencentCloudChat.TYPES.MSG_IMAGE){
        return item as MessageImage;
      }
      if(item.type === TencentCloudChat.TYPES.MSG_AUDIO){
        return item as MessageSound;
      }
      if(item.type === TencentCloudChat.TYPES.MSG_VIDEO){
        return item as MessageVideo;
      }
      if(item.type === TencentCloudChat.TYPES.MSG_FILE){
        return item as MessageFile;
      }
      if(item.type === TencentCloudChat.TYPES.MSG_CUSTOM){
        const sub_type =  item.payload?.extension?.sub_type;
        if(sub_type == 1){
          return item as MessageCustomDepartment;
        }
        if(sub_type == 2){
          return item as MessageCustomDoctor;
        }
        if(sub_type == 4){
          return item as MessageCustomPayment;
        }
        if(sub_type == 6){
          return item as MessageCustomUnknow;
        }
        if(sub_type == 8){
          return item as MessageCustomPatient;
        }
        if(sub_type == 9){
          return item as MessageCustomOrder;
        }
        if(sub_type == 10){
          return item as MessageCustomAdditionalFee;
        }
        if(sub_type == 11){
          return item as MessageCustomApproved;
        }
        if(sub_type == 12){
          return item as MessageCustomConsultation;
        }
        if(sub_type == 13){
          return item as MessageCustomDoctor2;
        }
        if(sub_type == 14){
          return item as MessageCustomThird;
        }
        if(sub_type == 15){
          return item as MessageCustomGroupNotice;
        }
        if(sub_type == 16){
          return item as MessageCustomHealthCard;
        }
        if(sub_type == 21){
          return item as MessageCustomRegistration;
        }
        if(sub_type == 99){
          return item as MessageCustomSystemNotice;
        }
      }
      if(item.type === TencentCloudChat.TYPES.MSG_MERGER){
        return item as MessageMerger;
      }
      if(item.type === TencentCloudChat.TYPES.MSG_LOCATION){
        return item as MessageLocation;
      }
      if(item.type === TencentCloudChat.TYPES.MSG_FACE){
        return item as MessageFace;
      }
      if(item.type === TencentCloudChat.TYPES.MSG_GRP_TIP){
        return item as MessageGroupTip;
      }
      if(item.type === TencentCloudChat.TYPES.MSG_GRP_SYS_NOTICE){
        return item as MessageGroupSystemNotice;
      }
      return item as Message;
    });
    return this._messageList;
  }

  get messageList():MessageListCustomType{
    return this._messageList;
  }

  sendText(to:string, payload: any, conversationType:ConversationType = TencentCloudChat.TYPES.CONV_GROUP):Promise<boolean>{
    const message = this.ctx.chat.createTextMessage({ to, conversationType, payload })
    return this.sendMessage(message);
  }

  sendAudio(to:string, payload: any = null, conversationType:ConversationType = TencentCloudChat.TYPES.CONV_GROUP): Promise<boolean>{
    // const message = this.ctx.chat.createAudioMessage({ to, conversationType, payload });
    const message = this.ctx.chat.createCustomMessage({ to, conversationType, payload: Object.assign({}, {
      data: '自定义单语音消息',
      description: '',
      extension: JSON.stringify(Object.assign({}, payload, { type: 3, sub_type: 52 }))
    }) });
    return this.sendMessage(message);
  }

  sendImage(to:string, payload: any = null, conversationType:ConversationType = TencentCloudChat.TYPES.CONV_GROUP): Promise<boolean>{
    // const message = this.ctx.chat.createImageMessage({ to, conversationType, payload });
    const message = this.ctx.chat.createCustomMessage({ to, conversationType, payload: Object.assign({}, {
      data: '自定义单图片消息',
      description: '',
      extension: JSON.stringify(Object.assign({}, payload, { type: 3, sub_type: 50 }))
    }) });
    return this.sendMessage(message);
  }

  async getMessageList(options: { conversationID: string }, emit: boolean = true, reset: boolean = false):Promise<MessageListCustomType>{
    if(reset || this._conversationID !== options.conversationID){
      this._messageList = [];
      this._nextReqMessageID = undefined;
      this._conversationID = options.conversationID;
    }
    if(this._nextReqMessageID || this._nextReqMessageID === undefined){
      const conversationID = options.conversationID;
      // 注意: 当nextReqMessageID有值时, 我们可以继续调用getMessageList方法, 获取更多历史消息列表.
      //       当nextReqMessageID为undefined时, 表示当前是初始化状态, 此时可以发起第一次请求消息列表.
      const _options:{ conversationID: string, nextReqMessageID?:string } = Object.assign({}, options);
      if(this._nextReqMessageID !== undefined){
        _options.nextReqMessageID = this._nextReqMessageID;
      }

      const { success } = await this.ctx.chat.getMessageList(_options);
      if(this._conversationID !== conversationID){
        return this.messageList;
      }
      this._nextReqMessageID = success?.data?.nextReqMessageID ?? '';
      this._messageList.unshift(...(success?.data?.messageList ?? [])); // 因为是历史消息, 所以添加到数组的开头.
      this.updateMessageList();
    }
    if(emit){
      this.ctx.mitt.emit(EVENT.MESSAGE, this.messageList);
    }
    return this.messageList;
  }

  async sendMessage(message:Message, options?:any):Promise<boolean>{
    const { success } = await this.ctx.chat.sendMessage(message, options);
    if(success){
      this.handleMessageReceived({ data: [message] });
    }
    return success ? true : false;
  }

  async resendMessage(message:Message, options?:any):Promise<boolean>{
    const { success } = await this.ctx.chat.resendMessage(message, options);
    if(success){
      this.handleMessageReceived({ data: [message] });
    }
    return success ? true : false;
  }
  async deleteMessage(messageList:Message[]):Promise<boolean>{
    const { success } = await this.ctx.chat.deleteMessage(messageList);
    return success ? true : false;
  }
}
