import TencentCloudChat from '@tencentcloud/lite-chat';
import { BaseService } from '../core/IMService';
import { EVENT } from '../constants';

export class TopicService extends BaseService {
  mount(): void {
    this.ctx.chat.on(TencentCloudChat.EVENT.TOPIC_CREATED, this.handleTopicCreated);
    this.ctx.chat.on(TencentCloudChat.EVENT.TOPIC_DELETED, this.handleTopicDeleted);
    this.ctx.chat.on(TencentCloudChat.EVENT.TOPIC_UPDATED, this.handleTopicUpdated);
  }
  unmount(): void {
    this.ctx.chat.off(TencentCloudChat.EVENT.TOPIC_CREATED, this.handleTopicCreated);
    this.ctx.chat.off(TencentCloudChat.EVENT.TOPIC_DELETED, this.handleTopicDeleted);
    this.ctx.chat.off(TencentCloudChat.EVENT.TOPIC_UPDATED, this.handleTopicUpdated);
  }

  private handleTopicCreated = (e:any):void => {}
  private handleTopicDeleted = (e:any):void => {}
  private handleTopicUpdated = (e:any):void => {}
}