import { logger } from '../utils';
import TencentCloudChat from '@tencentcloud/lite-chat';
import IMClient from './IMClient';
import { GroupService } from '../services/GroupService';

const dateFormat: (date: Date|number, fmt:string) => string = (date, fmt = 'yyyy-MM-dd HH:mm:ss') => {
  const [y, m, d, h, mm, s] = new Date(new Date(date).getTime() - new Date().getTimezoneOffset() * 60000).toISOString().match(/\d+/g) || [];
    // @ts-ignore
  return fmt.replace(/y{4}|y{2}|M{2}|M|d{2}|d|H{2}|H|h{2}|h|m{2}|m|s{2}|s|A|a/g, k => ({'yyyy':y, 'yy':y%100, 'MM':m, 'M': +m, 'dd':d, 'd':+d, 'HH':h, 'H':+h, 'hh':('0'+h%12).slice(-2), 'h':+h%12, 'mm':mm, 'm':+mm, 'ss':s, 's':+s, 'A':h<12?'AM':'PM', 'a':h<12?'am':'pm'})[k]);
}

const sex2str = (sex:number) => {
  if(sex == 1) return '男';
  return '女';
}
const ageUnit2str = (unit:number) => {
  if(unit == 1) return '岁';
  if(unit == 2) return '月';
  if(unit == 3) return '天';
  return '';
}
const visitType2str = (type:string) => {
  if(type == 'picture') return '图文问诊';
  if(type == 'video') return '视频问诊';
  return '快速咨询';
}
const fee2str = (fee:number) => {
  if(fee === 0) return '¥0.00';
  if(!fee) return '';
  return `¥${fee}`;
}

const processMessageItem = (item:any, index:number, arr:any[]) => {
  const message:Record<string, any> = {
		id: item.ID,
    type: '',
    from: item.from,
		isme: item.flow === 'out', // 当flow为out时为发送方(自己的消息)，否则为接收方(对方的消息)
		avatar: item.avatar,
		name: item.nameCard,
		new: !!item.isNewReceived,
    time: item.time * 1000, // 转成毫秒单位的时间戳
		timeDesc: dateFormat(item.time * 1000, 'MM-dd HH:mm'),
    conversationID: item.conversationID, // 保存conversationID方便核对数据
    _: item,  // 将原始item数据保存至_字段中, 方便业务端自行扩展处理.
	}

	if(item.type === 'TIMTextElem'){
		message.type = item.type;
		message.typeText = true;
    message.data = {
      text: item.payload.text,
    }
	}
	if(item.type === 'TIMImageElem'){
		message.type = item.type;
		message.typeImage = true;
    message.data = {
      thumb: item.payload.imageInfoArray?.find((item:any) => item.type == 1)?.url,
      url: item.payload.imageInfoArray?.find((item:any) => item.type == 0)?.url ?? item.payload.imageInfoArray?.find((item:any) => item.type == 2)?.url ?? item.payload.imageInfoArray?.find((item:any) => item.type == 1)?.url,
    }
	}
	if(item.type === 'TIMSoundElem'){
		message.type = item.type;
		message.typeSound = true;
    message.data = {
      url: item.payload.remoteAudioUrl,
      locUrl: item.payload.url,
      second: item.payload.second,
      size: item.payload.size,
    }
	}
	if(item.type === 'TIMCustomElem'){
    message.type = item.type;
    message.typeCustom = true;
    message.ext = Object.assign({}, item?.payload?.extension);
    message.subType = message?.ext?.sub_type;

    if(message.subType === 99){
			// 系统消息
			message.typeSystem = true;
      message.data = {
        text: item.payload.data,
      }
		}
		if(message.subType == 1){
			// 科室信息
      message.data = {
        id: message?.ext?.branchid,
        icon: message?.ext?.icon, // todo: 是否需要静态图标?
        title: message?.ext?.branchtitle,
      }
		}
		if(message.subType == 2 || message.subType == 13){
			// 医生信息
      message.data = {
        icon: 'doctor',
        title: '医生信息',
        info: {
          avatar: message?.ext?.avatar,
          branch: (message?.ext?.branch || message?.ext?.branch_title)?.split?.(',')?.join?.('、'),
          expert: message?.ext?.expert,
          introduction: message?.ext?.introduction,
          positiontitle: (message?.ext?.positiontitle || message?.ext?.position_title)?.split?.(',')?.join?.('、'),
          realname: message?.ext?.realname || message?.ext?.real_name,
        }
      }
		}
		if(message.subType == 4){
			// 处方支付
      message.data = {
        icon: '',
        title: '查看处方并支付',
        info: {
          icon: '',
          title: '电子处方',
          list: [
            { label: '患者', value: '' }, // 缺少患者信息
            { label: '金额', value: message?.ext?.order_info?.[0]?.real_amount ?? '', color: '#E98155' }, // 不确定金额来源
          ],
        }
      }
		}
		if(message.subType == 6){
			// 未知
		}
		if(message.subType == 8){
			// 确认就诊人
      message.data = {
        icon: '',
        title: '请确认患者信息是否正确',
        info: {
          icon: 'https://om.hongshanhis.com/static/img/assets/prescribe-inquiry.png', // todo: 图标
          title: '${message?.ext?.patient_name} (${sex2str(message?.ext?.member_info?.sex)} ${message?.ext?.member_info?.age}${ageUnit2str(message?.ext?.member_info?.age_unit)})', // 缺少患者信息
          list: [
            { label: '电话号码', value: message?.ext?.mp },
            { label: '身份证号', value: message?.ext?.cert_code },
            { label: '出生日期', value: message?.ext?.birth_date },
            { label: '所在地区', value: [message?.ext?.province, message?.ext?.city, message?.ext?.country].join('') },
            { label: '详细地址', value: message?.ext?.address },
          ],
        }
      }
		}
		if(message.subType == 9){
			// 确认订单
      message.data = {
        icon: '',
        title: '点击确认订单信息并支付',
        info: {
          list: [
            { label: '患者信息', value: message?.ext?.patient_name },
            { label: '咨询医生', value: message?.ext?.doctor_name },
            { label: '咨询科室', value: message?.ext?.branch },
            { label: '订单类型', value: message?.ext?.visit_type }, // 缺少咨询类型枚举
            { label: '预约时间', value: message?.ext?.visit_time },
            { label: '问诊费用', value: fee2str(message?.ext?.fee), color: '#E98155' },  // 费用单位未知
          ],
        }
      }
		}
		if(message.subType == 10){
			// 其它费用
      message.data = {
        icon: '',
        title: '查看其他费用并支付',
        info: {
          icon: 'https://om.hongshanhis.com/static/img/assets/static_other_order.png', // todo: 图标
          title: '其他费用',
          list: [
            { label: '患者', value: '' }, // 缺少患者信息
            { label: '金额', value: message?.ext?.real_amount ?? '', color: '#E98155' },
          ],
        }
      }
		}
		if(message.subType == 11){
			// 处方审核通过
      message.data = {
        icon: 'https://om.hongshanhis.com/static/img/assets/new-electronic.png',
        title: '电子处方',
        desc: '点击查看详情',
        pdf: message?.ext?.pdf ?? '',
      }
		}
		if(message.subType == 12){
			// 问诊信息
      message.data = {
        icon: 'https://om.hongshanhis.com/static/img/assets/prescribe-inquiry.png',
        title: '问诊信息',
        info: {
          list: [
            { label: '患者', value: message?.ext?.real_name },
            { label: '病情描述', value: message?.ext?.recount?.split?.(',')?.join?.('、') },
            { label: '药品信息', value: message?.ext?.drug?.join?.('、') },
          ],
        }
      }
		}
		if(message.subType == 14){
			// 三方购药: 超拼网
      message.data = {
        icon: 'https://om.hongshanhis.com/static/img/assets/prescribe-kaifang.png',
        text: '去买药'
      }
		}
		if(message.subType == 15){
			// 聊天框: 页眉/页脚
      // 原项目不使用message.subType为15来判断隐藏页脚, 所以这里暂时也不做处理保持与原逻辑相同.
      message.data = {
        text: item?.payload?.data,
        description: item?.payload?.description,
      }
		}
		if(message.subType == 16){
			// 健康信息
      message.data = {
        icon: 'health',
        title: '健康信息',
        info: {
          list: [
            { label: '肝肾功能', value: message?.ext?.healthy_condition?.liver_kidney_normal, color: '' },
            { label: '妊娠哺乳', value: message?.ext?.healthy_condition?.pregnancy, color: '' },
            { label: '过敏史', value: message?.ext?.healthy_condition?.allergy_history, color: '' },
            { label: '家族史', value: message?.ext?.healthy_condition?.family_history, color: '' },
            { label: '疾病史', value: message?.ext?.healthy_condition?.now_medical, color: '' },
          ].map(item => {
            if(item.value != '否'){
              // 如果健康信息的值是'否'时(说明此项有异常), 需要特别处理颜色让它高亮
              item.color = '#E98155';
            }
            return item;
          }),
        },
      }
		}
		if(message.subType == 21){
			// 挂号信息
      message.data = {
        icon: '',
        title: '点击确定预约挂号单并支付',
        info: {
          icon: '',
          title: `${message?.ext?.patient_name} (${sex2str(message?.ext?.member_info?.sex)} ${message?.ext?.member_info?.age}${ageUnit2str(message?.ext?.member_info?.age_unit)})`,
          list: [
            { label: '咨询医生', value: message?.ext?.doctor_name },
            { label: '咨询科室', value: message?.ext?.branch },
            { label: '订单类型', value: message?.ext?.visit_time },
            { label: '预约时间', value: visitType2str(message?.ext?.visit_type) },
            { label: '问诊费用', value: fee2str(message?.ext?.fee), color: '#E98155' },
          ]
        }
      }
		}
    if(message.subType == 50 || message.subType == 51 || message.subType == 52){
      // 50-自定义单图片消息  51-自定义单文件消息 52-自定义单语音消息
      message.data = Object.assign({}, message?.ext);
    }
	}

	if(message.type){
		// 只有设置了type属性的message才会显示, 这样我们就能过滤掉不需要显示的信息.
		
    if(message?.typeCustom && message?.from != 'administrator' && message?.subType == 15){
      message.data.showFootDescription = true;
    }

    if(message?.typeCustom && message?.from == 'administrator' && (message?.ext?.scence == 'prescription_verified' || message?.ext?.scence == 'prescription_refuse')){
      message.data.showFootDescription = false;
    }
    
    if(index <= 0 || (item.time - arr[index - 1]?.time) > (60 * 5)){
			// 第一条消息需要增加时间间隔
			// 两条消息间隔超过5分钟, 需要增加时间间隔
			const timeMessage = {
        id: Math.random().toString(32).slice(2),
        conversationID: '@TIM#SYSTEM',
				type: 'time',
				typeTime: true,
				data: {
          text: dateFormat(item.time * 1000, 'yyyy年MM月dd日 HH:mm'),
        }
			};
			return [timeMessage, message];
		}
		return message;
	}

	return null;
}

const processMessageName = (item:any = null, profile:any = {}) => {
  if(!item?.name){
    // 自己发送的消息不会产生message事件, 但是我们还是按标准流程来推送.
    // 不过推送过来的消息里nameCard字段缺失, 猜测是没有通过后端读取信息, 所以需要我们手动加上.
    // 当然其实也可以使用chat.message.getMessage()方法来刷新信息, 但是这样又会新增加分页加载的需求, 所以暂不考虑.
    if(profile){
      if(profile?.isPatient){
        item.name = `患者:${item.nick}`;
      }
      if(profile?.isAssistant){
        item.name = `医助:${item.nick}`;
      }
      if(profile?.isDoctor){
        item.name = `医生:${item.nick}`;
      }
      if(profile?.isThirdDoctor){
        item.name = `会诊医生:${item.nick}`;
      }
    }
  }
  return item;
}

/**
 * 对齐项目接口中的字段, 将接口字段映射为processMessageItem可以识别的字段.
 * 所以这里主要是将接口中的聊天记录字段与processMessageItem要处理的字段进行对齐, 以processMessageItem为准.
 * PS: 不理解为什么接口字段没有与原生messageList保持一致, 命名也太随意, 处处是坑.
 */
export const alignApiRecordData = (data:{ member: any[], record:any[] }) => {
  return data?.record?.map((item:any) => {
    item.groupProfile = data?.member?.find?.(o => o.communication_user_id == item.communication_user_id);
    item.ID = item.id;
    item.conversationID = item.communication_id;
    item.from = item.communication_user_id;
    item.isUser = item?.user_table == 'user' || item?.groupProfile?.user_type == 4;
    item.flow = item.isUser ? 'out' : 'in';
    item.avatar =  item.isUser ? item?.groupProfile?.user_head_img : item?.groupProfile?.admin_head_img;
    item.nameCard = item.communication_user_name_card || '';
    item.isNewReceived = false;
    item.time = item.time;
    item.payload = {}
    switch(item.mess_extend.extendType){
      case 'Text':
        item.type = 'TIMTextElem';
        item.payload.text = item?.mess ?? '';
        break;
      case 'Image':
        item.type = 'TIMImageElem';
        item.payload.imageInfoArray = [].concat(item?.mess_extend?.imageInfo);
        break;
      case 'Sound':
        item.type = 'TIMSoundElem';
        // todo: 语音消息数据对齐
        break;
      case 'File':
        item.type = 'TIMFileElem';
        break;
      case 'Custom':
        item.type = 'TIMCustomElem';
        item.payload.extension = Object.assign({}, item?.mess_extend?.extend, {
          sub_type: item?.mess_extend?.extend?.sub_type,
        });

        switch(item.payload.extension.sub_type){
          case 99:
            item.payload.data = item?.mess || '';
            break;
          case 1:
            // 待观察
            item.payload.extension = Object.assign({}, item?.mess_extend?.extend, item.payload.extension);
            break;
          case 2:
          case 13:
            item.payload.extension = Object.assign({}, item?.mess_extend?.extend, item.payload.extension);
            break;
          case 4:
            // 待观察
            item.payload.extension = Object.assign({}, item?.mess_extend?.extend, item.payload.extension);
            break;
          case 6:
            // 待观察
            item.payload.extension = Object.assign({}, item?.mess_extend?.extend, item.payload.extension);
            break;
          case 8:
            // 待观察
            item.payload.extension = Object.assign({}, item?.mess_extend?.extend, item.payload.extension);
            break;
          case 9:
            // 待观察
            item.payload.extension = Object.assign({}, item?.mess_extend?.extend, item.payload.extension);
            break;
          case 10:
            // 待观察
            item.payload.extension = Object.assign({}, item?.mess_extend?.extend, item.payload.extension);
            break;
          case 11:
            item.payload.extension = Object.assign({}, item?.mess_extend?.extend, item.payload.extension);
            break;
          case 12:
            item.payload.extension = Object.assign({}, item?.mess_extend?.extend, item.payload.extension);
            break;
          case 14:
            // 待观察
            item.payload.extension = Object.assign({}, item?.mess_extend?.extend, item.payload.extension);
            break;
          case 15:
            item.payload.data = item?.mess ?? '';
            item.payload.description = item?.mess_extend?.description || '';
            break;
          case 16:
            item.payload.extension = Object.assign({}, item?.mess_extend?.extend, item.payload.extension);
            break;
          case 21:
            // 待观察
            item.payload.extension = Object.assign({}, item?.mess_extend?.extend, item.payload.extension);
            break;
          case 50:
            // 待观察
            item.payload.extension = Object.assign({}, item?.mess_extend?.extend, item.payload.extension);
            break;
        }
        break;
      default:
        item.type = item.mess_extend.extendType;
        break;
    }
    return item;
  })?.map?.(processMessageItem)?.flat?.()?.map?.((item:any) => processMessageName(item, item.groupProfile))?.filter?.((item:any) => !!item) ?? [];
};

type GroupCallbackData = {
  avatar?: string,
  lastTime?: number,
  messageForShow?: string,
  type?: number,
  status?: number,
  _: any
}

type FacadeOptions = {
  userID: string,
  userSig: string,
  groupID?: string,
  conversationID?: string,
  level?: number,
  prepend?: number | number[],
  onMessage?: (messages: any[]) => void,
  onGroup?: (data: GroupCallbackData | any) => void,
  onConversation?: (conversations: any[]) => void,
  onFootDisaply?: (bol: boolean) => void,
  proxyServer?: string | undefined,
  fileUploadProxy?: string | undefined,
  fileDownloadProxy?: string | undefined,
  eventThrottling?: boolean | undefined,
}

type JoinChatOptions = Partial<FacadeOptions> & {
  groupID?: string,
  conversationID?: string,
}

type ActiveConversation = {
  conversationID: string,
  targetID: string,
  groupID?: string,
  userID?: string,
  conversationType: any,
  isGroup: boolean,
}

const resolveConversation = (options: JoinChatOptions): ActiveConversation | null => {
  const sourceConversationID = options.conversationID || (options.groupID ? options.groupID.replace(/^GROUP/i, '') : '');
  const conversationID = options.conversationID || (sourceConversationID ? `GROUP${sourceConversationID}` : '');

  if(!conversationID){
    return null;
  }

  if(/^GROUP/i.test(conversationID)){
    const groupID = conversationID.replace(/^GROUP/i, '');
    return {
      conversationID: `GROUP${groupID}`,
      targetID: groupID,
      groupID,
      conversationType: TencentCloudChat.TYPES.CONV_GROUP,
      isGroup: true,
    };
  }

  if(/^C2C/i.test(conversationID)){
    const userID = conversationID.replace(/^C2C/i, '');
    return {
      conversationID: `C2C${userID}`,
      targetID: userID,
      userID,
      conversationType: TencentCloudChat.TYPES.CONV_C2C,
      isGroup: false,
    };
  }

  logger.warn(`暂不支持进入该类型会话: ${conversationID}`);
  return null;
}

export default async function(SDKAppID: number = 0, options: FacadeOptions = { userID: "", userSig: "", level: 2 }
): Promise<{
  chat: IMClient,
  joinChat: (SDKAppIDOrOptions?: number | JoinChatOptions, options?: JoinChatOptions) => Promise<void>,
  selectConversation: (conversationIDOrOptions: string | JoinChatOptions, options?: JoinChatOptions) => Promise<void>,
  getConversationList: (options?: Array<string> | any) => Promise<any[]>,
  getActiveConversation: () => ActiveConversation | null,
  sendMessage: (params: { type:string, payload: any }) => Promise<void> }
> {
  const chat = IMClient.create(SDKAppID, Object.assign({}, {
    proxyServer: options?.proxyServer,
    fileUploadProxy: options?.fileUploadProxy,
    fileDownloadProxy: options?.fileDownloadProxy,
    eventThrottling: options?.eventThrottling
  }));

  if(options.level && options.level >= 0 && options.level <= 4){
    chat.setLogLevel(options.level as 0|1|2|3|4);
  }

  await chat.login({ userID: options.userID, userSig: options.userSig });

  let facadeOptions: FacadeOptions = options;
  let activeOptions: JoinChatOptions = options;
  let activeConversation: ActiveConversation | null = null;
  let activeGroupProfile:any = null;  // 记录下当前群聊的基本信息, 在每次joinChat和group事件中同步更新它.
  let selectTaskID = 0;
  
  const processGroupProfile = (group:any, currentOptions: JoinChatOptions = activeOptions) => {
    if(!group) return null;
    const profile = GroupService.handleGroupInfo(group);
    const groupCustomField = profile?.groupCustomField?.[0]?.value || profile?.groupCustomField?.[0] || {};
    const loginUserID = String(chat.getLoginUser() || currentOptions.userID || facadeOptions.userID);
    return Object.assign({}, profile, {
      isPatient: /^U\d+$/i.test(loginUserID),
      isAssistant: new RegExp(`H0*${groupCustomField?.assistant}$`, 'i').test(loginUserID),
      isDoctor: new RegExp(`H0*${groupCustomField?.doctor}$`, 'i').test(loginUserID),
      isThirdDoctor: new RegExp(`H0*${groupCustomField?.consultation_doctor}$`, 'i').test(loginUserID),
    }) 
  }

  const emitGroupProfile = (groupProfile:any, callbackOptions: JoinChatOptions = activeOptions, compact: boolean = false) => {
    if(!groupProfile) return;
    if(!compact){
      callbackOptions?.onGroup?.(groupProfile);
      return;
    }
    callbackOptions?.onGroup?.({
      avatar: groupProfile?.avatar, // 用户头像, 需要定时更新
      lastTime: groupProfile?.lastMessage?.lastTime * 1000, // 上次发送消息的时间戳(单位:毫秒)
      messageForShow: groupProfile?.lastMessage?.messageForShow,  // 上次发送的消息内容
      type: groupProfile?.groupCustomField?.[0]?.value?.type, // 消息类型(0-图文, 1-音频, 2-视频)
      status: groupProfile?.groupCustomField?.[0]?.value?.status, // 医生接诊状态(0-结束, 1-待接诊, 2-接诊中, 3-已接诊, 9-咨询中)
      _: groupProfile,  // 原始数据, 用于其它未知的逻辑处理
    });
  }

  const processActiveMessages = (list: any[], callbackOptions: JoinChatOptions = activeOptions): any[] => {
    if(!activeConversation) return [];
    const messages = list.map(processMessageItem).flat().map((item:any) => processMessageName(item, activeGroupProfile)).filter((item:any) => item?.conversationID == '@TIM#SYSTEM' || item?.conversationID == activeConversation?.conversationID).filter((item:any) => !!item);
      const msgNew = messages.find((item:any) => item.new) as any;

      if(msgNew && msgNew.typeCustom){
        if(msgNew?.from != 'administrator' && msgNew?._?.payload?.data == '开方等待'){
          // 根据旧项目逻辑, 显示页脚提示信息
        callbackOptions?.onFootDisaply?.(true);
        }
        if(msgNew?.from == 'administrator' && msgNew?._?.payload?.data == '处方已审核通过'){
          // 根据旧项目逻辑, 隐藏页脚提示信息
        callbackOptions?.onFootDisaply?.(false);
        }
      }

    if(callbackOptions?.prepend){
      const prepend = ([] as number[]).concat(callbackOptions?.prepend ?? []);
      return ([] as any[]).concat(
          (messages as any[]).filter((item:any) => prepend.indexOf(item.subType) >= 0),
          (messages as any[]).filter((item:any) => prepend.indexOf(item.subType) < 0),
      );
    }

    return messages;
  }

  chat.on('message', (list: any[]) => {
    if(!activeConversation) return;
    activeOptions?.onMessage?.(processActiveMessages(list));
  });

  chat.on('group', (groups:any[]) => {
    if(!activeConversation?.isGroup || !activeConversation.groupID) return;
    const group = groups.find((item:any) => item.groupID === activeConversation?.groupID);
    if(!group) return;
    activeGroupProfile = processGroupProfile(group);
    emitGroupProfile(activeGroupProfile, activeOptions, true);
  });

  chat.on('conversation', (list: any[]) => {
    facadeOptions?.onConversation?.(list);
  });

  const getConversationList = async (listOptions?: Array<string> | any): Promise<any[]> => {
    const list = await chat.conversation.getConversationList(listOptions);
    facadeOptions?.onConversation?.(list);
    return list;
  }

  const joinChat = async (SDKAppIDOrOptions: number | JoinChatOptions = 0, joinOptions: JoinChatOptions = {}) => {
    const currentJoinOptions: JoinChatOptions = typeof SDKAppIDOrOptions === 'number' ? joinOptions : SDKAppIDOrOptions;
    const mergedOptions: JoinChatOptions = Object.assign({}, facadeOptions, currentJoinOptions);
    const conversation = resolveConversation(mergedOptions);
    if(!conversation){
      logger.warn('未指定可进入的会话, 请传入 groupID 或 conversationID');
      return;
    }

    const taskID = ++selectTaskID;
    activeConversation = conversation;
    activeOptions = mergedOptions;
    facadeOptions = Object.assign({}, facadeOptions, mergedOptions);
    activeGroupProfile = null;

    if(conversation.isGroup && conversation.groupID){
      const group = await chat.group.getGroupProfile({ groupID: conversation.groupID });
      if(taskID !== selectTaskID) return;
      activeGroupProfile = processGroupProfile(group, mergedOptions);
      emitGroupProfile(activeGroupProfile, mergedOptions);
    }
    
    const list = await chat.message.getMessageList({ conversationID: conversation.conversationID }, false, true);
    if(taskID !== selectTaskID) return;
    mergedOptions?.onMessage?.(processActiveMessages(list, mergedOptions));
  }

  const selectConversation = async (conversationIDOrOptions: string | JoinChatOptions, selectOptions: JoinChatOptions = {}) => {
    if(typeof conversationIDOrOptions === 'string'){
      return joinChat(Object.assign({}, selectOptions, { conversationID: conversationIDOrOptions }));
    }
    return joinChat(conversationIDOrOptions);
  }

  const sendMessage = async (message: { type: string, payload: any  }) => {
    if(!chat.isReady()){
      logger.warn('SDK 未就绪, 请稍后再试');
      return;
    }
    if(!activeConversation){
      logger.warn('未进入任何会话, 无法发送消息');
      return;
    }
    switch(message.type){
			case 'text':
				await chat.message.sendText(activeConversation.targetID, message.payload, activeConversation.conversationType);
				break;
			case 'voice':
				await chat.message.sendAudio(activeConversation.targetID, message.payload, activeConversation.conversationType);
				break;
			case 'image':
				await chat.message.sendImage(activeConversation.targetID, message.payload, activeConversation.conversationType);
				break;
		}
	}

  await getConversationList();

  if(options.groupID || options.conversationID){
    await joinChat(SDKAppID, options);  // 默认获取指定会话的聊天记录.
  }

  return {
    chat,
    joinChat,
    selectConversation,
    getConversationList,
    getActiveConversation: () => activeConversation,
    sendMessage
  };
}
