import { EVENT } from '../constants';

// 定义通用的事件回调函数类型
type EventHandler = (...args: any[]) => void;

type EventName = keyof typeof EVENT | string;

export class IMEventBus {
  // 存储结构：Map<事件名, 回调函数数组>
  private listeners: Map<EventName, Array<EventHandler | Function>>;

  constructor() {
    this.listeners = new Map();
  }

  /**
   * 订阅事件
   * @param event 事件名
   * @param handler 回调函数
   */
  public on(event: EventName, handler: EventHandler | Function): void {
    const queue = this.listeners.get(event) || [];
    queue.push(handler);
    this.listeners.set(event, queue);
  }

  /**
   * 订阅一次性事件
   * 回调函数触发一次后会自动注销
   * @param event 事件名
   * @param handler 回调函数
   */
  public once(event: EventName, handler: EventHandler | Function): void {
    // 创建一个包装函数
    const onceHandler = (...args: any[]) => {
      // 1. 先把自己移除
      this.off(event, onceHandler);
      // 2. 再执行用户的原始逻辑
      handler(...args);
    };

    // 订阅这个包装函数
    this.on(event, onceHandler);
  }

  /**
   * 取消订阅
   * - 如果提供了 handler，只移除该回调
   * - 如果未提供 handler，移除该事件下的所有回调
   * @param event 事件名
   * @param handler (可选) 要移除的特定回调函数
   */
  public off(event: EventName, handler?: EventHandler | Function): void {
    // 情况1: 如果没有提供 handler，直接删除该事件的所有监听
    if (!handler) {
      this.listeners.delete(event);
      return;
    }

    // 情况2: 移除特定的 handler
    const queue = this.listeners.get(event);
    if (!queue) return;

    // 查找并移除
    const index = queue.indexOf(handler);
    if (index >= 0) {
      queue.splice(index, 1);
    }else {
      // 如果该事件没有剩余的监听器了，清理 Map key，释放内存
      this.listeners.delete(event);
    }
  }

  /**
   * 触发事件
   * @param event 事件名
   * @param args 传递的数据参数
   */
  public emit(event: EventName, ...args: any[]): void {
    const queue = this.listeners.get(event);
    if (!queue) return;

    // 浅拷贝队列: 防止在回调执行过程中，有代码调用了 off 导致 queue 长度变化，
    // 从而引起 forEach 循环索引错乱的问题。
    [...queue].forEach(handler => {
      try {
        handler(...args);
      } catch (error) {
        console.error(`[IMEventBus] Error in event handler for "${event}":`, error);
      }
    });
  }

  /**
   * 清除所有事件监听 (通常用于销毁 IMClient 实例时)
   */
  public clear(): void {
    this.listeners.clear();
  }
}