import TencentCloudChat from '@tencentcloud/lite-chat';
import { BaseService } from '../core/IMService';
import { EVENT } from '../constants';

export class AuthService extends BaseService {
  private AUTH_LOGIN:string = 'auth.login';
  private isLogined: boolean = false;


  mount(): void {
    this.ctx.chat.on(TencentCloudChat.EVENT.SDK_READY, this.handleSDKReady, this);
    this.ctx.chat.on(TencentCloudChat.EVENT.SDK_NOT_READY, this.handleSDKNotReady, this);
    // this.ctx.chat.on(TencentCloudChat.EVENT.KICKED_OUT, this.handleKickedOut, this);

    this.ctx.mitt.on(this.AUTH_LOGIN, this.handleLogin);
    // 为什么要使用this.AUTH_LOGIN而不是直接使用IM.LOGIN呢?
    // 因为希望所有的事件监听都通过mount/unmount来管理, 我们在login方法内部的SDK_READY回调函数内部虽然也可以直接触发LOGIN事件, 但是那就变得不受控了.
    // 所以我们要在SDK_READY回调内部通过emit(this.AUTH_LOGIN, e)来触发来传递到mount内部再通过mount/unmount来管理.
    // 这里有点绕但是还是为了统一管理事件的监听和解绑, 类的内部逻辑扭转可以通过定义私有事件来实现, 但是对外的事件必须要通过mount/unmount统一处理.
  }

  unmount(): void {
    this.ctx.chat.off(TencentCloudChat.EVENT.SDK_READY, this.handleSDKReady, this);
    this.ctx.chat.off(TencentCloudChat.EVENT.SDK_NOT_READY, this.handleSDKNotReady, this);
    // this.ctx.chat.off(TencentCloudChat.EVENT.KICKED_OUT, this.handleKickedOut, this);

    this.ctx.mitt.off(this.AUTH_LOGIN);
  }

  private handleLogin = (e: any): void => {
    this.ctx.mitt.emit(EVENT.LOGIN, e);
  }

  private handleSDKReady = (e: any): void => {
    this.ctx.mitt.emit(TencentCloudChat.EVENT.SDK_READY);
  }
  private handleSDKNotReady = (e: any): void => {
    this.ctx.mitt.emit(TencentCloudChat.EVENT.SDK_NOT_READY);
  }
  private handleKickedOut = (e: any): void => {
    this.isLogined = false;
    switch(e?.data?.type){
      case TencentCloudChat.TYPES.KICKED_OUT_MULT_ACCOUNT:
        // Web端，同一账号，多页面登录被踢
        this.ctx.mitt.emit(EVENT.LOGOUT, { message: '多实例登录被踢下线', data: null });
        break;
      case TencentCloudChat.TYPES.KICKED_OUT_MULT_DEVICE:
        // 同一账号，多端登录被踢
        this.ctx.mitt.emit(EVENT.LOGOUT, { message: '多端登录被踢下线', data: null });
        break;
      case TencentCloudChat.TYPES.KICKED_OUT_USERSIG_EXPIRED:
        // 签名过期
        this.ctx.mitt.emit(EVENT.LOGOUT, { message: '用户签名过期', data: null });
        break;
      case TencentCloudChat.TYPES.KICKED_OUT_REST_API:
        // REST API kick 接口踢出
        this.ctx.mitt.emit(EVENT.LOGOUT, { message: '用户被 REST API kick 接口踢掉', data: null });
        break;
      default:
        this.ctx.mitt.emit(EVENT.LOGOUT, { message: '退出登录', data: null });
        break;
    }
  }
  /**
   * 登录
   * @param userID 用户ID
   * @param userSig 腾讯云生成的签名
   */
  public async login(options: { userID: string, userSig: string }): Promise<{ success?:any, error?:any }> {
    return new Promise(async resolve => {
      this.isLogined = false;
      const that = this;
      const handleLoginSuccess = () => {
        that.isLogined = true;
        that.ctx.mitt.emit(that.AUTH_LOGIN, { message: '登录成功', data: options }); // 登录成功

        that.ctx.chat.on(TencentCloudChat.EVENT.KICKED_OUT, function onKickedOut(e:any) {
          that.ctx.chat.off(TencentCloudChat.EVENT.KICKED_OUT, onKickedOut);
          // 多实例时被踢下线, 此时内部会执行logout流程, 这里我们只需要执行Logout完成后的业务逻辑即可.
          that.handleKickedOut(e);
        });
        that.ctx.logger.info('登录成功');
        resolve({ success: { code: 0, data: '登录成功' }, error: null });
      }

      if(this.ctx.chat.isReady()){
        handleLoginSuccess();
        return;
      }

      this.ctx.chat.on(TencentCloudChat.EVENT.SDK_READY, (function onSdkReady() {
        that.ctx.chat.off(TencentCloudChat.EVENT.SDK_READY, onSdkReady);
        handleLoginSuccess();
      }));
      
      const { error } = await this.ctx.chat.login(options);
      if(error){
        this.ctx.logger.error('登录失败', error);
        resolve({ success: null, error });
      }
    });
  }

  /**
   * 登出
   */
  public async logout(): Promise<void> {
    if(!this.isLogined) return;
    const { success, error } = await this.ctx.chat.logout();
    if(success){
      this.handleKickedOut(success);
    }
    if(error){
      console.error('登出失败: ', error);
    }
  }
}
