import { IMEventBus } from './IMEventBus';
import { logger } from '../utils';

// 导入业务 Services
import { ClientService, TopicService, AuthService, MessageService, ConversationService, UserService, GroupService, CallService } from '../services';
import IMChat, { type IMChatSDK } from './IMChat';

declare const __TUI_CHAT_VERSION__: string;

export interface IMContext {
  chat: IMChatSDK;
  mitt: IMEventBus;
  logger: any
}

export default class IMClient {
  // --- 业务模块 (对外部可见) ---
  public client!: ClientService;
  public topic!: TopicService;
  public auth!: AuthService;
  public message!: MessageService;
  public conversation!: ConversationService;
  public user!: UserService;
  public group!: GroupService;
  public call!: CallService;

  // --- 内部实例 (内部使用) ---
  private chat!: IMChatSDK;
  private mitt!: IMEventBus;
  private isInitialized: boolean = false;

  private constructor(chat: IMChatSDK, context: IMContext) {
    this.isInitialized = false;

    this.chat = chat;
    this.mitt = context.mitt;

    this.setLogLevel(2); // 0-普通(日志较多,开发阶段使用) 1-生产阶段使用

    this.auth = new AuthService(context);
    this.message = new MessageService(context);
    this.conversation = new ConversationService(context);
    this.user = new UserService(context);
    this.group = new GroupService(context);
    this.call = new CallService(context);
    this.client = new ClientService(context);
    this.topic = new TopicService(context);

    this.mountSDKListeners();

    this.isInitialized = true;
    console.log('[IMClient] SDK 代理初始化成功');
  }

  public static create(SDKAppID: number = 0, options: { proxyServer?:string|undefined, fileUploadProxy?:string|undefined, fileDownloadProxy?:string|undefined, eventThrottling?:boolean|undefined } = {}): IMClient {
    // const chat = TencentCloudChat.create(Object.assign({}, options, { SDKAppID: Number(SDKAppID) }));
    const chat = IMChat.create(Object.assign({}, options, { SDKAppID: Number(SDKAppID) }));
    // 注意: 改用IMChat这个包装类来创建chat实例, 包装类内部对异步方法的返回结构进行了优化.

    return new IMClient(chat, {
      chat,
      mitt: new IMEventBus(),
      logger
    });
  }

  public login(options: { userID: string, userSig: string }): Promise<{ success?:any, error?:any }> {
    return this.auth.login(options);
  }

  public logout(): Promise<void> {
    return this.auth.logout();
  }

  public getLoginUser(): String {
    return this.chat.getLoginUser();
  }

  public getServerTime(): Number {
    return this.chat.getServerTime();
  }

  public isReady(): boolean {
    return this.chat.isReady();
  }

  public registerPlugin(options: any):IMChatSDK{
    this.chat.registerPlugin(options);
    return this.chat;
  }

  /**
   * 日志级别
   * @param level 0 普通级别，日志量较多，接入时建议使用
   *              1 release级别，SDK 输出关键信息，生产环境时建议使用
   *              2 告警级别，SDK 只输出告警和错误级别的日志
   *              3 错误级别，SDK 只输出错误级别的日志
   *              4 无日志级别，SDK 将不打印任何日志
   */
  public setLogLevel(level: 0|1|2|3|4 = 0):IMChatSDK{
    this.chat.setLogLevel(level);
    return this.chat;
  }



  public destroy(): void {
    if (this.chat) {
      this.unmountSDKListeners();
      this.chat.logout(); // 逻辑登出
      this.mitt.clear();
    }
    this.isInitialized = false;
  }

  private mountSDKListeners(): void {
    if (!this.chat) return;
    
    this.auth.mount();
    this.call.mount();
    this.client.mount();
    this.conversation.mount();
    this.group.mount();
    this.message.mount();
    this.topic.mount();
    this.user.mount();
  }

  /**
   * 解除监听
   */
  private unmountSDKListeners(): void {
    this.auth.unmount();
    this.call.unmount();
    this.client.unmount();
    this.conversation.unmount();
    this.group.unmount();
    this.message.unmount();
    this.topic.unmount();
    this.user.unmount();
  }

  /**
   * 暴露给 UI 的快捷订阅方法
   */
  public on(event: string, handler: Function): IMClient {
    this.mitt.on(event, handler);
    return this;
  }

  public off(event: string, handler?: Function): IMClient {
    this.mitt.off(event, handler);
    return this;
  }

  static get version(): string {
    return __TUI_CHAT_VERSION__;
  }
}