import TencentCloudChat from "@tencentcloud/lite-chat";
import type { ChatSDK } from "@tencentcloud/lite-chat";
import { logger } from "../utils";

type ExcludeMethods<T, K extends keyof T> = {
  [P in keyof T]: P extends K 
    ? T[P]  // 排除的方法保持原样
    : T[P] extends (...args: infer Args) => Promise<infer Data>
      ? (...args: Args) => Promise<
          | { success: Data; error: null }
          | { success: null; error: { code: number, message: string } }
        >
      : T[P]  // 同步方法保持原样
};

type CreateOption = {
  SDKAppID: number;
  proxyServer?: String | undefined;
  fileUploadProxy?: String | undefined;
  fileDownloadProxy?: String | undefined;
  scene?: String | undefined;
};

function createAsyncChat<T extends object, K extends keyof T>(
  service: T,
  excludeMethods: K[]
): ExcludeMethods<T, K> {
  const excludeSet = new Set(excludeMethods);
  
  const handler: ProxyHandler<T> = {
    get(target, prop: string | symbol) {
      const value = (target as any)[prop];
      
      if (typeof value === 'function') {
        const original = value as (...args: any[]) => any;
        
        if (excludeSet.has(prop as K)) {
          return original.bind(target);
        } else {
          return async (...args: any[]) => {
            try {
              const data = await original.apply(target, args);
              return { success: data, error: null };
            } catch (error: any) {
              const message = ((error?.message as string)?.split?.('"message": ')?.pop?.()?.split?.(', "code"')?.shift?.() ?? '')?.trim?.();
              if(message){
                logger.error(message);
              }else{
                logger.error(`调用失败, 具体原因请参考: https://cloud.tencent.com/document/product/269/1671 中${error?.code}错误码描述`);
              }
              return { success: null, error: { code: error?.code, message } };
            }
          };
        }
      }
      
      return value;
    }
  };
  
  return new Proxy(service, handler) as ExcludeMethods<T, K>;
}

const wrapMethods = ['getLoginUser', 'getServerTime', 'isReady', 'registerPlugin', 'setLogLevel', 'on', 'off', 'createTextMessage', 'createTextAtMessage', 'createImageMessage', 'createAudioMessage', 'createVideoMessage', 'createCustomMessage', 'createFaceMessage', 'createFileMessage', 'createLocationMessage', 'createMergerMessage', 'createForwardMessage', 'findMessage', 'getTotalUnreadMessageCount', 'getGroupOnlineMemberCount', 'addSignalingListener', 'removeSignalingListener', 'getSignalingInfo'] as const;
// 手动排除非异步函数, 这样剩下的所有函数我们都对它进行异步化封装以方便调用.

// export type IMChatSDK = ReturnType<typeof createAsyncChat<ChatSDK, typeof wrapMethods[number]>>;
export type IMChatSDK = ExcludeMethods<ChatSDK, typeof wrapMethods[number]>;

export default class IMChat {
  private sdkchat: IMChatSDK;
  public static create(options: CreateOption): IMChatSDK {
    // 创建实例并返回我们需要的sdkchat实例(通过getter属性访问并返回它).
    return new IMChat(options).chat;
  }

  private constructor(options: CreateOption) {
    // 禁止通过new的方式创建实例, 只使用IMChat.create()来创建实例, 与TencentCloudChat.create()创建实例一致.
    this.sdkchat = createAsyncChat(TencentCloudChat.create(options), [...wrapMethods]);
  }

  get chat(){
    return this.sdkchat;
  }
}