/**
 * 这里只根据业务需要自行定义扩展sdk事件的业务事件常量.
 * 因为sdk内部已经定义了大量可以利用的事件, 所以我们不需要再重新定义, 只需要根据业务需求定义需要的事件常量即可.
 * 不过在使用时切记要注意是TencentCloudChat.EVENT.XXX还是EVENT.XXX, 避免常量不存在的尴尬.
 */
export const EVENT = {
  LOGIN: 'login', // 登录系统, 不管是手动登出还是被踢下线都算登出
  LOGOUT: 'logout', // 登出系统
  MESSAGE: 'message', // 消息列表发生变化
  CONVERSATION: 'conversation',  // 对话列表发生变化
  GROUP: 'group', // 群聊列表发生变化
}