import TencentCloudChat from '@tencentcloud/lite-chat';
import { BaseService } from '../core/IMService';
import { EVENT } from '../constants';
import { logger } from '../utils';
import type { Group } from '../types/Group';

export class GroupService extends BaseService {
  private _groupList:any[] = [];
  public static handleGroupInfo = (item:any):any => {
    return {
      ...item,
      groupCustomField: item?.groupCustomField?.map?.((group:any) => {
        if(typeof group?.value === 'string'){
          try{
            group.value = JSON.parse(group.value);
          }catch(e){
            logger.warn(`解析群聊扩展数据失败 ${group.value}`);
            group.value = {};
          };
        }
        return group;
      }),
    }
  }
  
  mount(): void {
    this.ctx.chat.on(TencentCloudChat.EVENT.GROUP_LIST_UPDATED, this.handleGroupListUpdated);
    this.ctx.chat.on(TencentCloudChat.EVENT.GROUP_ATTRIBUTES_UPDATED, this.handleGroupAttributesUpdated);
    this.ctx.chat.on(TencentCloudChat.EVENT.GROUP_COUNTER_UPDATED, this.handleGroupCounterUpdated);
    this.ctx.chat.on(TencentCloudChat.EVENT.PINNED_GROUP_MESSAGE_UPDATED, this.handlePinnedGroupMessageUpdated);
  }

  unmount(): void {
    this.ctx.chat.off(TencentCloudChat.EVENT.GROUP_LIST_UPDATED, this.handleGroupListUpdated);
    this.ctx.chat.off(TencentCloudChat.EVENT.GROUP_ATTRIBUTES_UPDATED, this.handleGroupAttributesUpdated);
    this.ctx.chat.off(TencentCloudChat.EVENT.GROUP_COUNTER_UPDATED, this.handleGroupCounterUpdated);
    this.ctx.chat.off(TencentCloudChat.EVENT.PINNED_GROUP_MESSAGE_UPDATED, this.handlePinnedGroupMessageUpdated);
  }

  private handleGroupListUpdated = (e: any): void => {
    this._groupList = e?.data?.map?.(GroupService.handleGroupInfo);
    this.ctx.mitt.emit(TencentCloudChat.EVENT.GROUP_LIST_UPDATED, e.data);
    this.ctx.mitt.emit(EVENT.GROUP, this._groupList);
  }
  private handleGroupAttributesUpdated = (e: any): void => {
    const {
      groupID, // 群组ID
      groupAttributes, // 更新后的群属性
      updatedKeyList, // 群属性更新的 key 列表
      deletedKeyList, // 群属性删除的 key 列表
    } = e.data;
    this._groupList = this._groupList.map(item => {
      if(item.groupID == groupID){ // 这里的判断需要在真实环境测试, 因为不知道e.data是什么数据结构.
        // return GroupService.handleGroupInfo(e.data);
      }
      return item;
    })
    this.ctx.mitt.emit(TencentCloudChat.EVENT.GROUP_ATTRIBUTES_UPDATED, e.data);
    this.handleGroupListUpdated({
      data: this._groupList
    });
  }
  private handleGroupCounterUpdated = (e: any): void => {
    const { groupID, key, value } = e.data;
    // 这里也需要在真实环境判断, 因为不知道e的数据结构.
    this.ctx.mitt.emit(TencentCloudChat.EVENT.GROUP_COUNTER_UPDATED, e.data);
  }
  private handlePinnedGroupMessageUpdated = (e: any): void => {
    const { groupID, message, isPinned, operatorInfo } = e.data;
    this.ctx.mitt.emit(TencentCloudChat.EVENT.PINNED_GROUP_MESSAGE_UPDATED, e.data);
  }

  async isGroupMember(groupID: string): Promise<boolean>{
    const loginUserID = this.ctx.chat.getLoginUser();
    const groupMemberRet = await this.ctx.chat.getGroupMemberList({ groupID });
    if(groupMemberRet?.success?.data?.memberList?.find((member:any) => member.userID === loginUserID)){
      this.ctx.logger.info('您已是群成员');
      return true;
    }
    return false;
  }

  async getGroupList():Promise<any[]>{
    const { success } = await this.ctx.chat.getGroupList();
    return (success?.data?.groupList ?? [])?.map?.(GroupService.handleGroupInfo);
  }

  async getGroupProfile(options: { groupID:string, groupCustomFieldFilter?:string[] }): Promise<Group | null> {
    const { success } = await this.ctx.chat.getGroupProfile(options);
    return success?.data?.group ?? null;
  }

  async joinGroup(groupID: string, options?: { applyMessage?: string, type?: TencentCloudChat.TYPES }):Promise<boolean>{
    const isInGroup = await this.isGroupMember(groupID);
    if(!isInGroup){
      const { success } = await this.ctx.chat.joinGroup(Object.assign({}, options, { groupID }));
      if(success){
        const status = success.data.status;
        if(status === TencentCloudChat.TYPES.JOIN_STATUS_SUCCESS){
          this.ctx.logger.info('加群成功');
        }
        if(status === TencentCloudChat.TYPES.JOIN_STATUS_WAIT_APPROVAL){
          this.ctx.logger.info('等待管理员同意');
          return false;
        }
        if(status === TencentCloudChat.TYPES.JOIN_STATUS_ALREADY_IN_GROUP){
          this.ctx.logger.info('您已是群成员');
        }
        return true;
      }
    }
    return false;
  }
}