import TencentCloudChat from '@tencentcloud/lite-chat';
import { BaseService } from '../core/IMService';
import { EVENT } from '../constants';

export class ClientService extends BaseService {
  mount(): void {
    this.ctx.chat.on(TencentCloudChat.EVENT.NET_STATE_CHANGE, this.handleNetStateChange, this);
    this.ctx.chat.on(TencentCloudChat.EVENT.ALL_RECEIVE_MESSAGE_OPT_UPDATED, this.handleAllReceiveMessageOptUpdated, this);
  }
  unmount(): void {
    this.ctx.chat.off(TencentCloudChat.EVENT.NET_STATE_CHANGE, this.handleNetStateChange, this);
    this.ctx.chat.off(TencentCloudChat.EVENT.ALL_RECEIVE_MESSAGE_OPT_UPDATED, this.handleAllReceiveMessageOptUpdated, this);
  }

  private handleNetStateChange = (e: any): void => {
    this.ctx.mitt.emit(TencentCloudChat.EVENT.NET_STATE_CHANGE, e);
  }
  private handleAllReceiveMessageOptUpdated = (e: any): void => {
    this.ctx.mitt.emit(TencentCloudChat.EVENT.ALL_RECEIVE_MESSAGE_OPT_UPDATED, e);
  }
}