const PREFIX = '[IM-SDK]';

export const logger = {
  info: (msg: string, ...args: any[]) => {
    console.log(`${PREFIX}[INFO] ${msg}`, ...args);
  },
  warn: (msg: string, ...args: any[]) => {
    console.warn(`${PREFIX}[WARN] ${msg}`, ...args);
  },
  error: (msg: string, ...args: any[]) => {
    console.error(`${PREFIX}[ERROR] ${msg}`, ...args);
  }
};