import type { IMContext } from './IMClient';

export abstract class BaseService {

  /**
   * 上下文对象
   * 子类通过 this.ctx.mitt.emit() 向 UI或其它Service 抛出处理后的事件
   */
  protected ctx: IMContext;

  /**
   * 构造函数强制要求传入核心依赖
   * 这样保证了 Service 无法脱离 Client 独立存在
   */
  constructor(ctx: IMContext) {
    this.ctx = ctx;
  }

  abstract mount(): void;

  abstract unmount(): void;
}