import TencentCloudChat from '@tencentcloud/lite-chat';
import { BaseService } from '../core/IMService';
import { EVENT } from '../constants';

export class UserService extends BaseService {

  mount(): void {
    this.ctx.chat.on(TencentCloudChat.EVENT.PROFILE_UPDATED, this.handleUserProfileUpdated);
    this.ctx.chat.on(TencentCloudChat.EVENT.USER_STATUS_UPDATED, this.handleUserStatusUpdated);
    this.ctx.chat.on(TencentCloudChat.EVENT.BLACKLIST_UPDATED, this.handleBlacklistUpdated);
    this.ctx.chat.on(TencentCloudChat.EVENT.FRIEND_LIST_UPDATED, this.handleFriendListUpdated);
    this.ctx.chat.on(TencentCloudChat.EVENT.FRIEND_GROUP_LIST_UPDATED, this.handleFriendGroupListUpdated);
    this.ctx.chat.on(TencentCloudChat.EVENT.FRIEND_APPLICATION_LIST_UPDATED, this.handleFriendApplicationListUpdated);
    this.ctx.chat.on(TencentCloudChat.EVENT.MY_FOLLOWERS_LIST_UPDATED, this.handleMyFollowersListUpdated);
    this.ctx.chat.on(TencentCloudChat.EVENT.MY_FOLLOWING_LIST_UPDATED, this.handleMyFollowingListUpdated);
    this.ctx.chat.on(TencentCloudChat.EVENT.MUTUAL_FOLLOWERS_LIST_UPDATED, this.handleMutualFollowersListUpdated);
  }

  unmount(): void {
    this.ctx.chat.off(TencentCloudChat.EVENT.PROFILE_UPDATED, this.handleUserProfileUpdated);
    this.ctx.chat.off(TencentCloudChat.EVENT.USER_STATUS_UPDATED, this.handleUserStatusUpdated);
    this.ctx.chat.off(TencentCloudChat.EVENT.BLACKLIST_UPDATED, this.handleBlacklistUpdated);
    this.ctx.chat.off(TencentCloudChat.EVENT.FRIEND_LIST_UPDATED, this.handleFriendListUpdated);
    this.ctx.chat.off(TencentCloudChat.EVENT.FRIEND_GROUP_LIST_UPDATED, this.handleFriendGroupListUpdated);
    this.ctx.chat.off(TencentCloudChat.EVENT.FRIEND_APPLICATION_LIST_UPDATED, this.handleFriendApplicationListUpdated);
    this.ctx.chat.off(TencentCloudChat.EVENT.MY_FOLLOWERS_LIST_UPDATED, this.handleMyFollowersListUpdated);
    this.ctx.chat.off(TencentCloudChat.EVENT.MY_FOLLOWING_LIST_UPDATED, this.handleMyFollowingListUpdated);
    this.ctx.chat.off(TencentCloudChat.EVENT.MUTUAL_FOLLOWERS_LIST_UPDATED, this.handleMutualFollowersListUpdated);
  }

  private handleUserProfileUpdated = (e: any): void => {}
  private handleUserStatusUpdated = (e: any): void => {}
  private handleBlacklistUpdated = (e: any): void => {}
  private handleFriendListUpdated = (e: any): void => {}
  private handleFriendGroupListUpdated = (e: any): void => {}
  private handleFriendApplicationListUpdated = (e: any): void => {}
  private handleMyFollowersListUpdated = (e: any): void => {}
  private handleMyFollowingListUpdated = (e: any): void => {}
  private handleMutualFollowersListUpdated = (e: any): void => {}
}